//#region src/components/pulse/pulseBus.js
var listeners = /* @__PURE__ */ new Set();
function emit(event) {
	listeners.forEach((fn) => fn(event));
}
var pulse = {
	expression(name) {
		emit({
			type: "expression",
			expression: name
		});
	},
	say(message, options = {}) {
		emit({
			type: "say",
			message,
			actions: options.actions || [],
			expression: options.expression
		});
	},
	celebrate(message) {
		emit({
			type: "say",
			message,
			expression: "cheerful"
		});
	},
	formAction(action, payload = {}) {
		emit({
			type: "formAction",
			action,
			payload
		});
	},
	subscribe(fn) {
		listeners.add(fn);
		return () => listeners.delete(fn);
	}
};
