function gaussian(mean, stdDev) {
	const u1 = Math.max(rng(), 1e-9);
	const u2 = rng();
	return mean + Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2) * stdDev;
}
