function buildStudentRoster() {
	const roster = [];
	let counter = 1;
	for (const section of BLOCK_SECTIONS) for (let i = 0; i < section.students; i++) {
		const id = `stu-${counter}`;
		if (section.code === "BSIT-3A" && i < FIXED_TEST_STUDENTS.length) {
			const fixed = FIXED_TEST_STUDENTS[i];
			roster.push({
				id,
				name: fixed.name,
				email: fixed.email,
				section: section.code,
				yearLevel: section.yearLevel,
				courses: [{
					code: "WMAD 303-1",
					scores: fixed.scores,
					topics: fixed.topics
				}]
			});
		} else roster.push(buildGeneratedStudent(id, section));
		counter++;
	}
	return roster;
}
