function extractKeyPoints(body) {
	if (!body) return [];
	return body.split("\n").map((l) => l.trim()).filter((l) => l.length > 0).map((l) => l.replace(/^[•\-\*]\s*/, "").replace(/^\d+[\.\)]\s*/, "")).slice(0, 6);
}
