/**
* Convert an array of objects to CSV string.
* Handles values with commas, quotes, and newlines.
*/
function toCSV(data, columns) {
	if (!data.length) return "";
	const headers = columns || Object.keys(data[0]);
	const escape = (val) => {
		const str = val == null ? "" : String(val);
		if (str.includes(",") || str.includes("\"") || str.includes("\n")) return `"${str.replace(/"/g, "\"\"")}"`;
		return str;
	};
	return [headers.map(escape).join(","), ...data.map((row) => headers.map((h) => escape(row[h])).join(","))].join("\n");
}
/**
* Trigger a client-side file download from a string.
*/
function downloadBlob(content, filename, mimeType = "text/csv") {
	const blob = new Blob([content], { type: `${mimeType};charset=utf-8` });
	const url = URL.createObjectURL(blob);
	const a = document.createElement("a");
	a.href = url;
	a.download = filename;
	document.body.appendChild(a);
	a.click();
	document.body.removeChild(a);
	URL.revokeObjectURL(url);
}
