function rankCandidates(course) {
	const titleLower = course.title.toLowerCase();
	return INSTRUCTORS.map((inst) => {
		const specMatch = (SPECIALIZATION_KEYWORDS[inst.specialization] || []).filter((kw) => titleLower.includes(kw)).length;
		const score = (inst.hasMasters ? 100 : 0) + specMatch;
		const reason = [inst.hasMasters ? "Master's degree holder" : "No master's degree", specMatch > 0 ? `specialization match (${inst.specialization})` : "no specialization match"].join(" · ");
		return {
			...inst,
			specMatch,
			score,
			reason
		};
	}).sort((a, b) => b.score - a.score);
}
