var FAQ_ITEMS = [
	{
		q: "How does course loading work?",
		a: "The Dean or Associate Dean loads each released course to an instructor in Course Loading. AI can suggest a ranked candidate per course (Assist) or propose the whole load at once (Auto) — either way, priority 1 is a master's degree holder and priority 2 is specialization or forte in the course. Nothing is assigned until you confirm it."
	},
	{
		q: "How do I build a syllabus, and what happens to it after?",
		a: "On the Syllabus page, upload an existing file or build one with AI (Assist, section by section, or Auto for a full draft). It saves as Drafted either way — check and correct it, then Mark as Checked. Download it for the offline signatory route (Dean review → CAO approval → EVP noting), then upload the signed file back and extract the Course Outline. That activates the syllabus."
	},
	{
		q: "Why can't the Dean approve my syllabus inside EduPulse?",
		a: "The signatory chain happens outside the system, on the downloaded file. EduPulse tracks which station a syllabus is at (Drafted → Checked → Out for Approval → Approved → Active) but the actual review and signatures are offline."
	},
	{
		q: "How does AI courseware generation work?",
		a: "Once a syllabus is Active (its Course Outline is extracted), go to Courseware and generate by week, by term, or the whole outline. Each outline row's Contents + ILO drive learning materials, its Assessments column drives assessment items, and its TLA informs the activity type. Everything lands as a Draft — you finalize it, then publish. Only published items reach students."
	},
	{
		q: "Can students access unpublished courseware?",
		a: "No. Students only see items published to their block. Draft and finalized-but-unpublished items stay visible to the instructor only."
	},
	{
		q: "What is Student Monitoring, and is it my official grade sheet?",
		a: "No — it's for tracking only. Student Monitoring has two views: Assessment Scores (auto-recorded scores per student per course) and Learning Material Access (which documents students have opened). Your instructor can send reminders about missing activities or unopened files. Institutional grades (MG/TFG/FG) are computed in the official KCP grading sheet, outside EduPulse."
	},
	{
		q: "How do I view student performance?",
		a: "Performance shows topic mastery (mastered vs. needs-review) and score-threshold alerts for your own sections. College-wide syllabus status, delivery progress, and student oversight live in Monitor (Dean / Associate Dean)."
	},
	{
		q: "How do I choose an AI provider?",
		a: "Go to Settings > AI Provider (visible to instructors and the Dean/Associate Dean). Choose between a locally hosted model or a free API key — there is nothing else to configure."
	},
	{
		q: "What happens if I edit a syllabus mid-semester?",
		a: "EduPulse flags any published courseware that is now out of alignment with the updated outline row, so you know what needs a refresh."
	},
	{
		q: "What can Pulse (the AI guide) do for a student?",
		a: "Pulse can remind you about unopened materials or unanswered assessments and help you navigate the course. It will never answer or review your assessment items for you."
	}
];
